import React, { useState, useEffect } from 'react';
import './assets/styles/global.css';
import { Home, Users, BookOpen, MapPin, Camera, Star, Share2 } from 'lucide-react';

function App() {
  // Simulerar ett app-tillstånd
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showStoppedPanel, setShowStoppedPanel] = useState(false);
  const [isDriving, setIsDriving] = useState(true);

  // Simulerar att bilen stannar efter 3 sekunder
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsDriving(false);
      setShowStoppedPanel(true); // Panel kommer upp!
    }, 3000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div style={appContainerStyle}>
      {/* 1. MÖRK OCH VARM BAKGRUND */}

      {/* 2. NYTT HEADER-TEMA */}
      <header style={headerStyle}>
        <span style={logoStyle}>camper<span style={{fontWeight: '800'}}>BUDDY</span></span>
        <div style={drivingIndicator(isDriving)}>
          {isDriving ? "🚐 Rullar" : "🛑 Stannat"}
        </div>
      </header>

      {/* 3. DASHBOARD SOM "STYCKE-PANELER" */}
      <main style={mainContentStyle}>
        {activeTab === 'dashboard' && (
          <div style={dashboardSectionStyle}>
            {/* BULLIGA KORT PÅ DASHBOARDEN */}
            <div style={dashboardCard}>
              <h2 style={cardTitle}>Nerd-stats</h2>
              <p style={cardStat}>320 km <span style={statLabel}>- idag</span></p>
              <p style={cardStat}>1:00 tid <span style={statLabel}>- kört</span></p>
              <p style={cardStat}>13 stopp <span style={statLabel}>- loggat</span></p>
            </div>

            <div style={dashboardCard}>
              <h2 style={cardTitle}>Dagens Varning</h2>
              <p style={cardStat}>Hård vind</p>
              <p style={statLabel}>Kusten kl. 14:00</p>
            </div>
          </div>
        )}
        {activeTab === 'convoy' && <div>Konvoj Vy (Mock)</div>}
        {activeTab === 'logbook' && <div>Loggbok Vy (Mock)</div>}
      </main>

      {/* 4. DEN PROAKTIVA PANELEN SOM KOMMER NEDIFRÅN (NÄR MAN STANNAR) */}
      <div style={stoppedPanelStyle(showStoppedPanel)}>
        <h2 style={stoppedPanelTitle}>Härlig plats! Vad vill du göra?</h2>
        <div style={stoppedPanelButtons}>
          <button style={actionBtn} onClick={() => setShowStoppedPanel(false)}>
            <Camera color="white" size={24} />
            <span style={actionBtnLabel}>Fota platsen</span>
          </button>
          <button style={actionBtn} onClick={() => setShowStoppedPanel(false)}>
            <Star color="white" size={24} />
            <span style={actionBtnLabel}>Spara i loggbok</span>
          </button>
          <button style={actionBtn} onClick={() => setShowStoppedPanel(false)}>
            <Share2 color="white" size={24} />
            <span style={actionBtnLabel}>Dela position</span>
          </button>
        </div>
        <button style={closePanelBtn} onClick={() => setShowStoppedPanel(false)}>Senare</button>
      </div>

      {/* 5. FLYTANDE APP-NAVIGATION (MÖRK OCH VARM) */}
      <nav style={navWrapperStyle(showStoppedPanel)}>
        <div style={navInnerStyle}>
          <NavButton 
            active={activeTab === 'dashboard'} 
            onClick={() => setActiveTab('dashboard')} 
            icon={<Home size={22} />} 
            label="Hem" 
          />
          <NavButton 
            active={activeTab === 'convoy'} 
            onClick={() => setActiveTab('convoy')} 
            icon={<Users size={22} />} 
            label="Konvoj" 
          />
          <NavButton 
            active={activeTab === 'logbook'} 
            onClick={() => setActiveTab('logbook')} 
            icon={<BookOpen size={22} />} 
            label="Logg" 
          />
        </div>
      </nav>
    </div>
  );
}

// --- SUB-KOMPONENT ---
const NavButton = ({ active, onClick, icon, label }) => (
  <button onClick={onClick} style={navBtnStyle(active)}>
    {React.cloneElement(icon, { strokeWidth: active ? 2.5 : 2 })}
    <span style={labelStyle(active)}>{label}</span>
  </button>
);


// --- DESIGNKOD MED URSKOGS-TEMAT (WARM, DARK, BUBBLY) ---

const appContainerStyle = {
  maxWidth: '480px',
  margin: '0 auto',
  minHeight: '100vh',
  // NYTT TEMAFÄRGERS-SCHEMA (MÖRKARE OCH VARMARE)
  backgroundColor: '#1A2F1C', // Djup ur-skogsmörk grön (inte mörkgrå)
  color: '#F7F1E1', // Varm beige/kräm text
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  boxShadow: '0 0 40px rgba(0,0,0,0.1)',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif',
};

// HEADER OCH LOGO (VARMA TONER)
const headerStyle = {
  padding: '25px 25px 15px',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
};

const logoStyle = {
  fontSize: '22px',
  color: '#F7F1E1', // Varm kräm
  letterSpacing: '-0.5px'
};

const drivingIndicator = (isDriving) => ({
  backgroundColor: isDriving ? '#C06C4C' : '#F7F1E1', // Rostbrunt för körning, kräm för stopp
  color: isDriving ? 'white' : '#1A2F1C',
  padding: '6px 14px',
  borderRadius: '25px', // Riktigt runda hörn
  fontSize: '13px',
  fontWeight: '600',
  boxShadow: '0 5px 15px rgba(0,0,0,0.1)',
});

// MAIN CONTENT OCH DASHBOARD KORT
const mainContentStyle = {
  padding: '10px 20px 180px 20px',
  flex: 1
};

const dashboardSectionStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: '15px'
};

const dashboardCard = {
  // MYCKET BULLIGARE FÖRMOR
  backgroundColor: 'rgba(247, 241, 225, 0.08)', // Subtil varm mörk panel
  padding: '25px',
  borderRadius: '35px', // Extremt bullig!
  border: '1px solid rgba(247, 241, 225, 0.05)',
